Touch event handling depends on the platform you're working with. Here are the most common approaches:

## Web (JavaScript)

### Basic Touch Events
```javascript
// Touch start, move, and end
element.addEventListener('touchstart', function(e) {
    const touch = e.touches[0];
    console.log('Touch started at:', touch.clientX, touch.clientY);
    e.preventDefault(); // Prevent default behavior
});

element.addEventListener('touchmove', function(e) {
    const touch = e.touches[0];
    console.log('Touch moved to:', touch.clientX, touch.clientY);
    e.preventDefault();
});

element.addEventListener('touchend', function(e) {
    console.log('Touch ended');
    e.preventDefault();
});
```

### Multi-touch Handling
```javascript
element.addEventListener('touchstart', function(e) {
    console.log('Number of fingers:', e.touches.length);

    // Handle each touch point
    for (let i = 0; i < e.touches.length; i++) {
        const touch = e.touches[i];
        console.log(`Touch ${i}:`, touch.clientX, touch.clientY);
    }
});
```

### Unified Touch/Mouse Events
```javascript
function getEventPos(e) {
    if (e.touches) {
        return { x: e.touches[0].clientX, y: e.touches[0].clientY };
    }
    return { x: e.clientX, y: e.clientY };
}

// Handle both mouse and touch
element.addEventListener('mousedown', handleStart);
element.addEventListener('touchstart', handleStart);

function handleStart(e) {
    const pos = getEventPos(e);
    console.log('Started at:', pos.x, pos.y);
}
```

